  `technical_doc` text COMMENT '技术文档（文档链接或内容）',
  `attachment` varchar(500) DEFAULT NULL COMMENT '附件（文件路径）',
  `damage_desc` text COMMENT '损坏说明（主机状态异常时必填）',
  `accessory_desc` text COMMENT '配件情况',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `manage_code` (`manage_code`),
  KEY `idx_principal_id` (`principal_id`),
  KEY `idx_equipment_source` (`equipment_source`)
