  `id` varchar(36) NOT NULL COMMENT '报废单ID',
  `order_no` varchar(50) NOT NULL COMMENT '报废单号 格式：BF-20260219-001',
  `applicant_id` varchar(36) NOT NULL COMMENT '申请人ID',
  `applicant` varchar(100) NOT NULL COMMENT '申请人姓名',
  `apply_date` date NOT NULL COMMENT '申请日期',
  `equipment_id` varchar(36) NOT NULL COMMENT '设备ID',
  `equipment_code` varchar(50) DEFAULT NULL COMMENT '管理编号(冗余)',
  `equipment_name` varchar(200) DEFAULT NULL COMMENT '设备名称(冗余)',
  `equipment_category` varchar(50) DEFAULT NULL COMMENT '设备类型(冗余)',
  `purchase_date` date DEFAULT NULL COMMENT '购置日期(冗余)',
  `purchase_price` decimal(12,2) DEFAULT NULL COMMENT '购置价格(冗余)',
  `used_years` decimal(3,1) DEFAULT NULL COMMENT '使用年限',
  `scrap_reason` text NOT NULL COMMENT '报废原因',
  `residual_value` decimal(12,2) DEFAULT '0.00' COMMENT '残值评估',
  `disposal_method` enum('destroy','sell','donate') DEFAULT NULL COMMENT '处理方式',
  `disposed_at` timestamp NULL DEFAULT NULL COMMENT '处理时间',
  `disposal_notes` text COMMENT '处理备注',
  `status` enum('draft','pending','approved','rejected','disposed') DEFAULT 'draft' COMMENT '单据状态',
  `approval_id` varchar(36) DEFAULT NULL COMMENT '关联审批ID',
  `approved_at` timestamp NULL DEFAULT NULL COMMENT '审批通过时间',
  `approved_by` varchar(36) DEFAULT NULL COMMENT '审批人ID',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `idx_applicant` (`applicant_id`),
  KEY `idx_equipment` (`equipment_id`),
  KEY `idx_status` (`status`),
  KEY `idx_equipment_scrap_orders_order_no` (`order_no`),
  KEY `idx_equipment_scrap_orders_equipment` (`equipment_id`),
  KEY `idx_equipment_scrap_orders_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='设备报废单';
