--
-- Table structure for table `equipment_transfer_orders`
--

DROP TABLE IF EXISTS `equipment_transfer_orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipment_transfer_orders` (
  `id` varchar(36) NOT NULL COMMENT '调拨单ID',
  `order_no` varchar(50) NOT NULL COMMENT '调拨单号 格式：DB-20260219-001',
  `transfer_scene` enum('A','B','C') NOT NULL COMMENT '调拨场景 A-国内有库存/B-国内无库存/C-国外项目间',
  `applicant_id` varchar(36) NOT NULL COMMENT '申请人ID',
  `applicant` varchar(100) NOT NULL COMMENT '申请人姓名',
  `apply_date` date NOT NULL COMMENT '申请日期',
  `equipment_id` varchar(36) DEFAULT NULL COMMENT '设备ID',
  `equipment_code` varchar(50) DEFAULT NULL COMMENT '管理编号(冗余)',
  `equipment_name` varchar(200) DEFAULT NULL COMMENT '设备名称(冗余)',
  `equipment_category` varchar(50) DEFAULT NULL COMMENT '设备类型(冗余)',
  `from_location_type` enum('warehouse','project') NOT NULL COMMENT '调出位置类型',
  `from_warehouse_id` varchar(36) DEFAULT NULL COMMENT '调出仓库ID',
  `from_warehouse_name` varchar(200) DEFAULT NULL COMMENT '调出仓库名称(冗余)',
  `from_project_id` varchar(36) DEFAULT NULL COMMENT '调出项目ID',
  `from_project_name` varchar(200) DEFAULT NULL COMMENT '调出项目名称(冗余)',
  `from_manager_id` varchar(36) DEFAULT NULL COMMENT '调出方负责人ID',
  `from_manager` varchar(100) DEFAULT NULL COMMENT '调出方负责人(冗余)',
  `to_location_type` enum('warehouse','project') NOT NULL COMMENT '调入位置类型',
  `to_warehouse_id` varchar(36) DEFAULT NULL COMMENT '调入仓库ID',
  `to_warehouse_name` varchar(200) DEFAULT NULL COMMENT '调入仓库名称(冗余)',
  `to_project_id` varchar(36) DEFAULT NULL COMMENT '调入项目ID',
  `to_project_name` varchar(200) DEFAULT NULL COMMENT '调入项目名称(冗余)',
  `to_manager_id` varchar(36) DEFAULT NULL COMMENT '调入方负责人ID',
  `to_manager` varchar(100) DEFAULT NULL COMMENT '调入方负责人(冗余)',
  `solution` enum('borrow','purchase') DEFAULT NULL COMMENT '处理方案',
  `estimated_arrival` date DEFAULT NULL COMMENT '预计到货时间',
  `transfer_reason` text NOT NULL COMMENT '调拨原因',
  `estimated_ship_date` date DEFAULT NULL COMMENT '预计发货日期',
  `estimated_arrival_date` date DEFAULT NULL COMMENT '预计到达日期',
  `transport_method` enum('land','air','express','self') DEFAULT NULL COMMENT '运输方式',
  `tracking_no` varchar(100) DEFAULT NULL COMMENT '物流单号',
  `notes` text COMMENT '备注',
  `status` enum('draft','pending_from','pending_to','shipping','receiving','completed','rejected','withdrawn') DEFAULT 'draft' COMMENT '单据状态',
  `approval_id` varchar(36) DEFAULT NULL COMMENT '关联审批ID',
  `from_approved_at` timestamp NULL DEFAULT NULL COMMENT '调出方审批时间',
  `from_approved_by` varchar(36) DEFAULT NULL COMMENT '调出方审批人ID',
  `from_approval_comment` text COMMENT '调出方审批意见',
  `to_approved_at` timestamp NULL DEFAULT NULL COMMENT '调入方审批时间',
  `to_approved_by` varchar(36) DEFAULT NULL COMMENT '调入方审批人ID',
  `to_approval_comment` text COMMENT '调入方审批意见',
  `shipped_at` timestamp NULL DEFAULT NULL COMMENT '发货时间',
  `shipped_by` varchar(36) DEFAULT NULL COMMENT '发货人ID',
  `shipping_no` varchar(100) DEFAULT NULL COMMENT '发货单号',
  `shipping_attachment` varchar(500) DEFAULT NULL COMMENT '发货凭证附件',
  `received_at` timestamp NULL DEFAULT NULL COMMENT '收货时间',
  `received_by` varchar(36) DEFAULT NULL COMMENT '收货人ID',
  `receive_status` enum('normal','damaged','missing','partial') DEFAULT NULL COMMENT '收货状态',
  `receive_comment` text COMMENT '收货备注',
  `total_items` int DEFAULT '0' COMMENT '设备总数',
  `total_quantity` int DEFAULT '0' COMMENT '设备总数量',
  `transfer_type` enum('single','batch') DEFAULT 'single' COMMENT '调拨类型',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `idx_applicant` (`applicant_id`),
  KEY `idx_equipment` (`equipment_id`),
  KEY `idx_from_warehouse` (`from_warehouse_id`),
  KEY `idx_from_project` (`from_project_id`),
  KEY `idx_to_warehouse` (`to_warehouse_id`),
  KEY `idx_to_project` (`to_project_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='设备调拨单';
/*!40101 SET character_set_client = @saved_cs_client */;

