--
-- Table structure for table `workflow_execution_logs`
--

DROP TABLE IF EXISTS `workflow_execution_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_execution_logs` (
  `id` varchar(36) NOT NULL COMMENT '日志ID',
  `execution_id` varchar(36) NOT NULL COMMENT '执行ID',
  `action` varchar(50) NOT NULL COMMENT '操作类型：process_start/task_complete/node_execute等',
  `process_key` varchar(100) DEFAULT NULL COMMENT '流程标识',
  `instance_id` varchar(36) DEFAULT NULL COMMENT '流程实例ID',
  `task_id` varchar(36) DEFAULT NULL COMMENT '任务ID',
  `node_id` varchar(36) DEFAULT NULL COMMENT '节点ID',
  `node_name` varchar(200) DEFAULT NULL COMMENT '节点名称',
  `node_type` varchar(50) DEFAULT NULL COMMENT '节点类型',
  `business_key` varchar(200) DEFAULT NULL COMMENT '业务标识',
  `initiator` json DEFAULT NULL COMMENT '发起人信息',
  `operator` json DEFAULT NULL COMMENT '操作人信息',
  `result` varchar(50) DEFAULT NULL COMMENT '操作结果',
  `error` text COMMENT '错误信息',
  `reason` text COMMENT '原因说明',
  `metadata` json DEFAULT NULL COMMENT '元数据',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_execution_id` (`execution_id`),
  KEY `idx_instance_id` (`instance_id`),
  KEY `idx_task_id` (`task_id`),
  KEY `idx_action` (`action`),
  KEY `idx_process_key` (`process_key`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_workflow_execution_logs_instance_id` (`instance_id`),
  KEY `idx_workflow_execution_logs_action` (`action`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='流程执行日志表';
/*!40101 SET character_set_client = @saved_cs_client */;

