DROP TABLE IF EXISTS `workflow_executions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_executions` (
  `id` varchar(36) NOT NULL COMMENT '执行ID',
  `instance_id` varchar(36) NOT NULL COMMENT '流程实例ID',
  `parent_id` varchar(36) DEFAULT NULL COMMENT '父执行ID',
  `node_id` varchar(100) NOT NULL COMMENT '当前节点ID',
  `node_name` varchar(200) DEFAULT NULL COMMENT '节点名称',
  `node_type` varchar(50) DEFAULT NULL COMMENT '节点类型',
  `variables` json DEFAULT NULL COMMENT '局部变量',
  `status` enum('active','completed','cancelled') DEFAULT 'active' COMMENT '状态',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `completed_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_instance` (`instance_id`),
  KEY `idx_parent` (`parent_id`),
  KEY `idx_node` (`node_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='执行实例表';
/*!40101 SET character_set_client = @saved_cs_client */;

