CREATE TABLE `workflow_instance_history` (
  `id` varchar(36) NOT NULL COMMENT '历史记录ID',
  `instance_id` varchar(36) NOT NULL COMMENT '流程实例ID',
  `from_status` varchar(50) DEFAULT NULL COMMENT '原状态',
  `to_status` varchar(50) NOT NULL COMMENT '新状态',
  `operator_id` varchar(36) DEFAULT NULL COMMENT '操作人ID',
  `operator_name` varchar(100) DEFAULT NULL COMMENT '操作人姓名',
  `reason` text COMMENT '变更原因',
  `metadata` json DEFAULT NULL COMMENT '元数据',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_instance_id` (`instance_id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='流程实例状态历史表';
