--
-- Table structure for table `workflow_instances`
--

DROP TABLE IF EXISTS `workflow_instances`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_instances` (
  `id` varchar(36) NOT NULL COMMENT '实例ID',
  `definition_id` varchar(36) NOT NULL COMMENT '流程定义ID',
  `definition_key` varchar(100) NOT NULL COMMENT '流程标识',
  `definition_version` int NOT NULL COMMENT '流程版本',
  `category` varchar(50) DEFAULT NULL COMMENT '流程分类',
  `business_key` varchar(100) DEFAULT NULL COMMENT '业务关联键',
  `business_id` varchar(36) DEFAULT NULL COMMENT '业务实体ID',
  `title` varchar(300) DEFAULT NULL COMMENT '实例标题',
  `initiator_id` varchar(36) DEFAULT NULL COMMENT '发起人ID',
  `initiator_name` varchar(100) DEFAULT NULL COMMENT '发起人姓名',
  `variables` json DEFAULT NULL COMMENT '流程变量',
  `status` enum('running','suspended','completed','terminated','rejected') DEFAULT 'running' COMMENT '状态',
  `start_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '开始时间',
  `end_time` timestamp NULL DEFAULT NULL COMMENT '结束时间',
  `duration` bigint DEFAULT NULL COMMENT '耗时(毫秒)',
  `result` enum('approved','rejected','withdrawn','terminated','skipped') DEFAULT NULL COMMENT '流程结果',
  `current_node_id` varchar(100) DEFAULT NULL COMMENT '当前活动节点ID',
  `current_node_name` varchar(200) DEFAULT NULL COMMENT '当前活动节点名称',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_definition` (`definition_id`),
  KEY `idx_definition_key` (`definition_key`),
  KEY `idx_business` (`business_key`,`business_id`),
  KEY `idx_initiator` (`initiator_id`),
  KEY `idx_status` (`status`),
  KEY `idx_start_time` (`start_time`),
  KEY `idx_category_status` (`category`,`status`),
  KEY `idx_start_time_status` (`start_time`,`status`),
  KEY `idx_end_time` (`end_time`),
  KEY `idx_workflow_instances_initiator_status` (`initiator_id`,`status`),
  KEY `idx_workflow_instances_definition_status` (`definition_id`,`status`),
  KEY `idx_workflow_instances_business_key` (`business_key`),
  KEY `idx_workflow_instances_category_status` (`category`,`status`),
  KEY `idx_workflow_instances_created_at` (`created_at` DESC)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='流程实例表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `workflow_instances`
--

LOCK TABLES `workflow_instances` WRITE;
