--
-- Table structure for table `workflow_tasks`
--

DROP TABLE IF EXISTS `workflow_tasks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_tasks` (
  `id` varchar(36) NOT NULL COMMENT '任务ID',
  `instance_id` varchar(36) NOT NULL COMMENT '流程实例ID',
  `execution_id` varchar(36) DEFAULT NULL COMMENT '执行实例ID',
  `node_id` varchar(100) NOT NULL COMMENT '节点ID',
  `task_def_key` varchar(100) DEFAULT NULL COMMENT '任务定义键',
  `name` varchar(200) NOT NULL COMMENT '任务名称',
  `description` text COMMENT '任务描述',
  `assignee_id` varchar(36) DEFAULT NULL COMMENT '处理人ID',
  `assignee_name` varchar(100) DEFAULT NULL COMMENT '处理人姓名',
  `candidate_users` json DEFAULT NULL COMMENT '候选用户列表',
  `candidate_groups` json DEFAULT NULL COMMENT '候选组列表',
  `priority` int DEFAULT '50' COMMENT '优先级(0-100)',
  `due_date` timestamp NULL DEFAULT NULL COMMENT '到期时间',
  `claim_time` timestamp NULL DEFAULT NULL COMMENT '认领时间',
  `variables` json DEFAULT NULL COMMENT '任务变量',
  `status` enum('created','assigned','in_progress','completed','cancelled') DEFAULT 'created' COMMENT '状态',
  `approval_mode` enum('or_sign','and_sign','sequential','vote') DEFAULT 'or_sign' COMMENT '审批模式：or_sign/and_sign/sequential/vote',
  `vote_threshold` int DEFAULT '1' COMMENT '票决阈值',
  `result` enum('approved','rejected','withdrawn','delegated','transferred','skipped') DEFAULT NULL COMMENT '处理结果',
  `comment` text COMMENT '审批意见',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `started_at` timestamp NULL DEFAULT NULL COMMENT '开始处理时间',
  `completed_at` timestamp NULL DEFAULT NULL COMMENT '完成时间',
  `duration` bigint DEFAULT NULL COMMENT '耗时(毫秒)',
  PRIMARY KEY (`id`),
  KEY `idx_instance` (`instance_id`),
  KEY `idx_execution` (`execution_id`),
  KEY `idx_assignee` (`assignee_id`),
  KEY `idx_status` (`status`),
  KEY `idx_due_date` (`due_date`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_assignee_status` (`assignee_id`,`status`),
  KEY `idx_created_status` (`created_at`,`status`),
  KEY `idx_completed_status` (`completed_at`,`status`),
  KEY `idx_workflow_tasks_instance_status` (`instance_id`,`status`),
  KEY `idx_workflow_tasks_assignee_status` (`assignee_id`,`status`),
  KEY `idx_workflow_tasks_created_at` (`created_at` DESC)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='任务实例表';
/*!40101 SET character_set_client = @saved_cs_client */;

