DROP TABLE IF EXISTS `workflow_variable_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_variable_history` (
  `id` varchar(36) NOT NULL COMMENT '历史ID',
  `instance_id` varchar(36) NOT NULL COMMENT '流程实例ID',
  `execution_id` varchar(36) DEFAULT NULL COMMENT '执行实例ID',
  `task_id` varchar(36) DEFAULT NULL COMMENT '任务ID',
  `variable_name` varchar(100) NOT NULL COMMENT '变量名',
  `variable_type` varchar(50) DEFAULT NULL COMMENT '变量类型',
  `old_value` text COMMENT '旧值',
  `new_value` text COMMENT '新值',
  `operator_id` varchar(36) DEFAULT NULL COMMENT '操作人ID',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_instance` (`instance_id`),
  KEY `idx_variable_name` (`variable_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='流程变量历史表';
